1	const PROCESSING_FEE = 5;
2	
3	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	const COMPONENT_PREMIUM = 25;
11	const COMPONENT_BLOCK_PREMIUM = 60;
12	const COMPONENT_BLOCK_SIZE = 3;
13	
14	const KNOWN_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	const isMainItem = (type: string): boolean => MAIN_ITEM_PREMIUMS.hasOwnProperty(type);
17	
18	const isComponent = (type: string): boolean => !isMainItem(type);
19	
20	const isKnownType = (type: string): boolean =>
21	  isMainItem(type) || KNOWN_COMPONENT_TYPES.has(type);
22	
23	const CURSED_SURCHARGE_RATE = 0.5;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
26	
27	const calculateItemSurcharges = (item: { type: string; cursed?: boolean; enchantment?: number }): number => {
28	  const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
29	  let surcharges = 0;
30	  if (item.cursed) {
31	    surcharges += base * CURSED_SURCHARGE_RATE;
32	  }
33	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
34	    surcharges += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
35	  }
36	  return surcharges;
37	};
38	
39	const calculateComponentGroupPremium = (count: number): number =>
40	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
41	
42	const INSURANCE_VALUES: Record<string, number> = {
43	  sword: 1000,
44	  amulet: 600,
45	  staff: 800,
46	  potion: 400,
47	};
48	const COMPONENT_INSURANCE_VALUE = 250;
49	const DEDUCTIBLE = 100;
50	
51	const getInsuranceValue = (type: string): number =>
52	  INSURANCE_VALUES[type] ?? COMPONENT_INSURANCE_VALUE;
53	
54	const FIRST_INSURANCE_RATE = 0.1;
55	const LOYALTY_DISCOUNT_RATE = 0.2;
56	const LOYALTY_THRESHOLD_YEARS = 2;
57	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
58	
59	const calculatePremium = (items: { type: string; cursed?: boolean; enchantment?: number }[], yearsWithMHPCO: number, isFollowUp: boolean): number => {
60	  for (const item of items) {
61	    if (!isKnownType(item.type)) {
62	      throw new Error(`Unknown item type: ${item.type}`);
63	    }
64	  }
65	
66	  let policyBasePremium = 0;
67	  let itemSurcharges = 0;
68	
69	  const componentCounts: Record<string, number> = {};
70	  for (const item of items) {
71	    if (isComponent(item.type)) {
72	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
73	    } else {
74	      policyBasePremium += MAIN_ITEM_PREMIUMS[item.type] ?? 0;
75	      itemSurcharges += calculateItemSurcharges(item);
76	    }
77	  }
78	
79	  for (const count of Object.values(componentCounts)) {
80	    policyBasePremium += calculateComponentGroupPremium(count);
81	  }
82	
83	  const policyModifierRate = FIRST_INSURANCE_RATE
84	    - (yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0)
85	    - (isFollowUp ? FOLLOW_UP_DISCOUNT_RATE : 0);
86	  const policyModifiers = policyBasePremium * policyModifierRate;
87	
88	  return Math.ceil(policyBasePremium + itemSurcharges + policyModifiers + PROCESSING_FEE);
89	};
90	
91	export function processScenario(scenario: { customer: { yearsWithMHPCO: number }; steps: any[] }): { results: unknown[] } {
92	  let quoteCount = 0;
93	  const policies: Map<number, { items: any[]; remainingCap: number }> = new Map();
94	
95	  const results = scenario.steps.map((step, index) => {
96	    if (step.op === "quote") {
97	      const isFollowUp = quoteCount > 0;
98	      quoteCount++;
99	      const items = step.items ?? [];
100	      const premium = calculatePremium(items, scenario.customer.yearsWithMHPCO, isFollowUp);
101	      const insuranceSum = items.reduce((sum: number, item: any) => sum + getInsuranceValue(item.type), 0);
102	      policies.set(index, { items, remainingCap: insuranceSum * 2 });
103	      return { premium };
104	    } else {
105	      const policy = policies.get(step.policy)!;
106	      let totalPayout = 0;
107	      for (const damage of step.incident.damages) {
108	        const payout = Math.max(0, damage.amount - DEDUCTIBLE);
109	        totalPayout += payout;
110	      }
111	      if (totalPayout > policy.remainingCap) {
112	        totalPayout = policy.remainingCap;
113	      }
114	      policy.remainingCap -= totalPayout;
115	      return { payout: Math.floor(totalPayout), remainingCap: policy.remainingCap };
116	    }
117	  });
118	  return { results };
119	}
