const calculateClaimPayout = (
  damages: { itemType: string; amount: number }[],
  remainingCap: number,
): { payout: number; remainingCap: number } => {
  let totalPayout = 0;
  for (const damage of damages) {
    totalPayout += Math.max(0, damage.amount - DEDUCTIBLE);
  }
  if (totalPayout > remainingCap) {
